    try:
        data = json.loads(export_body or "{}")
    except Exception:
        data = {"success": False, "error": "export endpoint returned non-JSON"}
    success = bool(data.get("success"))
    blocked = bool(data.get("blocked"))
    download_url = data.get("download_url") or ""
